import fs from "fs";
import path from "path";
import { Document } from "llamaindex";
import { LlamaCloudIndex } from "llama-cloud-services";

async function main() {
  try {
    // 1. Read trial_id
    const trialId = fs.readFileSync("/logs/artifacts/trial_id", "utf-8").trim();
    const indexName = `harbor-managed-index-ts-${trialId}`;

    // 2. Load local corpus
    const dataDir = "/home/user/index_task_ts/data";
    const files = ["facts.txt", "history.txt"];
    const documents: Document[] = [];

    for (const file of files) {
      const filePath = path.join(dataDir, file);
      const content = fs.readFileSync(filePath, "utf-8");
      documents.push(new Document({ text: content, metadata: { filename: file } }));
    }

    console.log(`Ingesting ${documents.length} documents into index: ${indexName}`);

    // 3. Create LlamaCloud managed index with MANAGED_OPENAI_EMBEDDING
    const index = await LlamaCloudIndex.fromDocuments({
      documents,
      name: indexName,
      projectName: "Default",
      apiKey: process.env.LLAMA_CLOUD_API_KEY,
      verbose: true
    }, {
      embedding: {
        type: "MANAGED_OPENAI_EMBEDDING",
        component: {
          model_name: "openai-text-embedding-3-small"
        }
      }
    } as any);

    // 4. Use as retriever
    const retriever = index.asRetriever();
    const query = "What is the capital of Atlantis?";
    const nodes = await retriever.retrieve({ query });

    // 5. Build retrieval result string
    let retrievalResult = "";
    for (const node of nodes) {
      retrievalResult += node.node.getContent() + "\n";
    }

    // 6. Write to output.log
    const logContent = `Index name: ${indexName}\n\nRetrieved context:\n${retrievalResult}`;
    fs.writeFileSync("/home/user/index_task_ts/output.log", logContent);

    console.log("Task completed successfully.");
    process.exit(0);
  } catch (error) {
    console.error("Error:", error);
    process.exit(1);
  }
}

