    const index = await LlamaCloudIndex.fromDocuments({
      documents,
      name: indexName,
      projectName: "Default",
      apiKey: process.env.LLAMA_CLOUD_API_KEY,
      verbose: true
    });

    // 4. Use as retriever
    const retriever = index.asRetriever();
    const query = "What is the capital of Atlantis?";
    const nodes = await retriever.retrieve({ query });

    // 5. Build retrieval result string
    let retrievalResult = "";
    for (const node of nodes) {
      retrievalResult += node.node.getContent() + "\n";
    }

    // 6. Write to output.log
    const logContent = `Index name: ${indexName}\n\nRetrieved context:\n${retrievalResult}`;
    fs.writeFileSync("/home/user/index_task_ts/output.log", logContent);

    console.log("Task completed successfully.");
    process.exit(0);
  } catch (error) {
    console.error("Error:", error);
    process.exit(1);
  }
}

